const renderTimelineIcon = (type: string) => {
    switch (type) {
        case 'login': return <FaSignInAlt color="var(--success)"/>;
        case 'course': return <FaPlayCircle color="var(--p-purple)"/>;
        case 'exam': return <FaFileAlt color="var(--warning)"/>;
        case 'error': return <FaExclamationTriangle color="var(--danger)"/>;
        default: return <FaClock color="var(--txt-mut)"/>;
    }
};

export default function StudentsManagement() {
    const { showToast } = useToast();
    const [mounted, setMounted] = useState(false);

    const [view, setView] = useState<'dashboard' | 'profile'>('dashboard');
    const [dashboardTab, setDashboardTab] = useState<'table' | 'map'>('table');
    const [profileTab, setProfileTab] = useState<'timeline' | 'academic' | 'financial'>('timeline');
    
    const [selectedStudent, setSelectedStudent] = useState<any>(null);
    const [selectedIds, setSelectedIds] = useState<number[]>([]);
    const [isBulkBalanceModalOpen, setIsBulkBalanceModalOpen] = useState(false);
    const [bulkAmount, setBulkAmount] = useState('');

    const [searchQuery, setSearchQuery] = useState('');
    const [selectedGrade, setSelectedGrade] = useState('all');
    const [selectedStatus, setSelectedStatus] = useState<'all' | 'active' | 'banned'>('all');

    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<any>({});

    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 20;

    const [students, setStudents] = useState<any[]>([]);
    const [hoveredRegion, setHoveredRegion] = useState<any>(null);

    useEffect(() => { 
        setStudents(generateMockStudents());
        setMounted(true); 
    }, []);

    const filteredStudents = useMemo(() => {
        return students.filter(student => {
            const query = searchQuery.trim().toLowerCase();
            const matchesSearch = student.name.toLowerCase().includes(query) || student.phone.includes(query) || student.serial.toLowerCase().includes(query);
            const matchesGrade = selectedGrade === 'all' || student.grade === selectedGrade;
            const matchesStatus = selectedStatus === 'all' || student.status === selectedStatus;
            return matchesSearch && matchesGrade && matchesStatus;
        });
    }, [students, searchQuery, selectedGrade, selectedStatus]);

    const totalPages = Math.ceil(filteredStudents.length / itemsPerPage);
    const currentStudents = filteredStudents.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

    const activeCount = students.filter(s => s.status === 'active').length;
    const bannedCount = students.filter(s => s.status === 'banned').length;

    const handleSearch = (val: string) => { setSearchQuery(val); setCurrentPage(1); setSelectedIds([]); };
    const handleGradeFilter = (val: string) => { setSelectedGrade(val); setCurrentPage(1); setSelectedIds([]); };
    const handleStatusFilter = (val: any) => { setSelectedStatus(val); setCurrentPage(1); setSelectedIds([]); };

    const toggleSelectAll = () => setSelectedIds(selectedIds.length === currentStudents.length ? [] : currentStudents.map(s => s.id));
    const toggleSelectOne = (id: number) => setSelectedIds(prev => prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]);
    
    const handleBulkResetIP = () => { showToast(`تم تصفير الـ IP لعدد ${selectedIds.length} طالب بنجاح!`, 'success'); setSelectedIds([]); };
    const handleBulkBan = () => { 
        setStudents(students.map(s => selectedIds.includes(s.id) ? { ...s, status: 'banned' } : s));
        showToast(`تم حظر ${selectedIds.length} طالب بنجاح!`, 'error'); 
        setSelectedIds([]); 
    };
    const handleBulkUnban = () => { 
        setStudents(students.map(s => selectedIds.includes(s.id) ? { ...s, status: 'active' } : s));
        showToast(`تم فك الحظر عن ${selectedIds.length} طالب بنجاح!`, 'success'); 
        setSelectedIds([]); 
    };
    const handleBulkMessage = () => { showToast(`تم إرسال الرسالة إلى ${selectedIds.length} طالب بنجاح!`, 'info'); setSelectedIds([]); };
    const handleBulkAddBalance = () => {
        if(!bulkAmount) return;
        showToast(`تم إضافة ${bulkAmount} ج.م بنجاح! 💰`, 'success');
        setIsBulkBalanceModalOpen(false); setBulkAmount(''); setSelectedIds([]);
    };

    const toggleStudentBan = () => {
        const newStatus = selectedStudent.status === 'banned' ? 'active' : 'banned';
        setStudents(students.map(s => s.id === selectedStudent.id ? { ...s, status: newStatus } : s));
        setSelectedStudent({ ...selectedStudent, status: newStatus });
        showToast(newStatus === 'banned' ? 'تم حظر الطالب بنجاح! 🚫' : 'تم فك حظر الطالب بنجاح! ✅', newStatus === 'banned' ? 'error' : 'success');
    };

    const resetIP = (studentName: string) => showToast(`تم تصفير الأجهزة للطالب ${studentName} بنجاح! 🔄`, 'success');
    const refundCourse = () => showToast('تم استرداد الرصيد للمحفظة بنجاح! 💰', 'success');

    const saveStudentEdit = () => {
        setStudents(students.map(s => s.id === editFormData.id ? { ...s, ...editFormData } : s));
        if (selectedStudent && selectedStudent.id === editFormData.id) setSelectedStudent({ ...selectedStudent, ...editFormData });
        setIsEditModalOpen(false); showToast('تم حفظ التعديلات بنجاح! 💾', 'success');
    };

    if (!mounted) return null;

    if (view === 'dashboard') {
        return (
            <div style={{ animation: 'fadeIn 0.5s ease' }}>
                <style>{`
                    .desktop-table { display: table; }
                    .mobile-cards { display: none; }
                    @media (max-width: 768px) { .desktop-table { display: none; } .mobile-cards { display: flex; flex-direction: column; gap: 15px; } }
                    .egypt-map-path { transition: all 0.3s ease; stroke: rgba(255,255,255,0.4); stroke-width: 0.5px; cursor: pointer; }
                    .egypt-map-path:hover { stroke: #fff; stroke-width: 2px; filter: brightness(1.2) drop-shadow(0 0 10px rgba(255,255,255,0.8)); z-index: 10; }
                    .stat-card { background: var(--card); padding: 20px; border-radius: 15px; border: 1px solid rgba(255,255,255,0.05); display: flex; align-items: center; gap: 15px; transition: 0.3s; cursor: pointer; }
                    .stat-card:hover { transform: translateY(-5px); box-shadow: 0 10px 20px rgba(0,0,0,0.3); border-color: rgba(255,255,255,0.2); }
                `}</style>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '15px' }}>
                    <div>
                        <h1 style={{ fontSize: '1.8rem', color: 'var(--txt)', fontWeight: 900, display: 'flex', alignItems: 'center', gap: '10px' }}>
                            <FaUserGraduate style={{ color: 'var(--p-purple)' }} /> شؤون الطلاب
                        </h1>
                        <p style={{ color: 'var(--txt-mut)' }}>نظام الإدارة الشامل، العمليات المجمعة، والتحليلات.</p>
                    </div>
                    <Button variant="primary" icon={<FaFileExcel />} onClick={() => showToast('جاري استخراج الشيت...', 'info')} style={{ background: '#217346', color: 'white' }}>
                        استخراج (Excel)
                    </Button>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px', marginBottom: '25px' }}>
                    <div className="stat-card" onClick={() => { setDashboardTab('table'); handleStatusFilter('all'); }}>
                        <div style={{ width: '50px', height: '50px', borderRadius: '12px', background: 'rgba(108,92,231,0.1)', display: 'flex', justifyContent: 'center', alignItems: 'center', color: 'var(--p-purple)', fontSize: '1.5rem' }}><FaUsers /></div>
                        <div>
                            <div style={{ color: 'var(--txt-mut)', fontSize: '0.9rem', fontWeight: 'bold' }}>إجمالي الطلاب</div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 900, color: 'var(--txt)' }}>{students.length}</div>
                        </div>
                    </div>
                    <div className="stat-card" onClick={() => { setDashboardTab('table'); handleStatusFilter('active'); }} style={{ border: selectedStatus === 'active' ? '1px solid var(--success)' : '' }}>
                        <div style={{ width: '50px', height: '50px', borderRadius: '12px', background: 'rgba(46, 204, 113, 0.1)', display: 'flex', justifyContent: 'center', alignItems: 'center', color: 'var(--success)', fontSize: '1.5rem' }}><FaCheckCircle /></div>
                        <div>
                            <div style={{ color: 'var(--txt-mut)', fontSize: '0.9rem', fontWeight: 'bold' }}>حسابات نشطة</div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 900, color: 'var(--txt)' }}>{activeCount}</div>
                        </div>
                    </div>
                    <div className="stat-card" onClick={() => { setDashboardTab('table'); handleStatusFilter('banned'); }} style={{ border: selectedStatus === 'banned' ? '1px solid var(--danger)' : '' }}>
                        <div style={{ width: '50px', height: '50px', borderRadius: '12px', background: 'rgba(231, 76, 60, 0.1)', display: 'flex', justifyContent: 'center', alignItems: 'center', color: 'var(--danger)', fontSize: '1.5rem' }}><FaBan /></div>
                        <div>
                            <div style={{ color: 'var(--txt-mut)', fontSize: '0.9rem', fontWeight: 'bold' }}>حسابات محظورة</div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 900, color: 'var(--danger)' }}>{bannedCount}</div>
                        </div>
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '10px', marginBottom: '25px', background: 'var(--card)', padding: '10px', borderRadius: '15px', border: '1px solid rgba(255,255,255,0.05)' }}>
                    <button onClick={() => setDashboardTab('table')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', fontWeight: 'bold', cursor: 'pointer', transition: '0.3s', background: dashboardTab === 'table' ? 'var(--p-purple)' : 'transparent', color: dashboardTab === 'table' ? 'white' : 'var(--txt)' }}><FaSearch style={{ margin: '0 8px' }} /> قاعدة بيانات الطلاب</button>
                    <button onClick={() => setDashboardTab('map')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', fontWeight: 'bold', cursor: 'pointer', transition: '0.3s', background: dashboardTab === 'map' ? 'var(--danger)' : 'transparent', color: dashboardTab === 'map' ? 'white' : 'var(--txt)' }}><FaMapMarkerAlt style={{ margin: '0 8px' }} /> خريطة المحافظات التفاعلية</button>
                </div>

                {dashboardTab === 'table' && (
                    <>
                        <div style={{ background: 'var(--card)', padding: '20px', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', marginBottom: '20px', display: 'flex', gap: '15px', flexWrap: 'wrap' }}>
                            <div style={{ flex: '1 1 300px', position: 'relative' }}>
                                <FaSearch style={{ position: 'absolute', right: '15px', top: '15px', color: 'var(--p-purple)' }} />
                                <input type="text" placeholder="بحث باسم، تليفون، كود..." value={searchQuery} onChange={(e) => handleSearch(e.target.value)} style={{ width: '100%', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(108,92,231,0.3)', padding: '12px 40px 12px 15px', borderRadius: '10px', color: 'var(--txt)', outline: 'none' }} />
                            </div>
                            <select value={selectedGrade} onChange={(e) => handleGradeFilter(e.target.value)} style={{ flex: '1 1 200px', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(108,92,231,0.3)', padding: '12px', borderRadius: '10px', color: 'var(--txt)', outline: 'none' }}>
                                <option value="all">كل المراحل الدراسية</option>
                                <option value="الصف الأول الثانوي">الصف الأول الثانوي</option>
                                <option value="الصف الثاني الثانوي">الصف الثاني الثانوي</option>
                                <option value="الصف الثالث الثانوي">الصف الثالث الثانوي</option>
                            </select>
                            <select value={selectedStatus} onChange={(e) => handleStatusFilter(e.target.value)} style={{ flex: '1 1 200px', background: 'rgba(0,0,0,0.2)', border: selectedStatus === 'banned' ? '1px solid var(--danger)' : '1px solid rgba(108,92,231,0.3)', padding: '12px', borderRadius: '10px', color: selectedStatus === 'banned' ? 'var(--danger)' : 'var(--txt)', outline: 'none', fontWeight: 'bold' }}>
                                <option value="all">كل الحالات</option>
                                <option value="active">حسابات نشطة ✅</option>
                                <option value="banned">حسابات محظورة 🚫</option>
                            </select>
                        </div>

                        {selectedIds.length > 0 && (
                            <div style={{ background: 'linear-gradient(90deg, var(--p-purple), #ff007f)', padding: '15px 20px', borderRadius: '15px', marginBottom: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: 'white', animation: 'fadeIn 0.3s ease', flexWrap: 'wrap', gap: '15px', boxShadow: '0 10px 20px rgba(108,92,231,0.3)' }}>
                                <div style={{ fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '10px' }}>
                                    <FaCheckSquare size={20} /> تم تحديد {selectedIds.length} طالب
                                </div>
                                <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                                    <button onClick={handleBulkResetIP} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', padding: '8px 15px', borderRadius: '8px', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' }}><FaSyncAlt /> تصفير IP</button>
                                    <button onClick={() => setIsBulkBalanceModalOpen(true)} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', padding: '8px 15px', borderRadius: '8px', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' }}><FaWallet /> شحن محفظة</button>
                                    {selectedStatus === 'banned' ? (
                                        <button onClick={handleBulkUnban} style={{ background: 'var(--success)', border: 'none', padding: '8px 15px', borderRadius: '8px', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' }}><FaUnlock /> فك الحظر</button>
                                    ) : (
                                        <button onClick={handleBulkBan} style={{ background: 'var(--danger)', border: 'none', padding: '8px 15px', borderRadius: '8px', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' }}><FaBan /> حظر</button>
                                    )}
                                </div>
                            </div>
                        )}

                        <div style={{ background: 'var(--card)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', overflow: 'hidden' }}>
                            <table className="desktop-table" style={{ width: '100%', textAlign: 'right', borderCollapse: 'collapse' }}>
    <thead>
        <tr style={{ background: 'rgba(255,255,255,0.05)', color: 'var(--txt-mut)' }}>
            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)', width: '50px' }}>
                <input type="checkbox" checked={selectedIds.length === currentStudents.length && currentStudents.length > 0} onChange={toggleSelectAll} style={{ width: '18px', height: '18px', accentColor: 'var(--p-purple)', cursor: 'pointer' }} />
            </th>
            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>الكود</th>
            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>الاسم والتليفون</th>
            
            {/* 💡 عمود الباسورد رجع أهو */}
            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>الباسورد</th>
            
            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>الحالة</th>
            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>المرحلة</th>
            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)', textAlign: 'center' }}>إدارة</th>
        </tr>
    </thead>
    <tbody>
        {currentStudents.map(student => (
            <tr key={student.id} style={{ borderBottom: '1px dashed rgba(255,255,255,0.05)', background: selectedIds.includes(student.id) ? 'rgba(108,92,231,0.05)' : student.status === 'banned' ? 'rgba(231,76,60,0.05)' : 'transparent' }}>
                <td style={{ padding: '15px' }}>
                    <input type="checkbox" checked={selectedIds.includes(student.id)} onChange={() => toggleSelectOne(student.id)} style={{ width: '18px', height: '18px', accentColor: 'var(--p-purple)', cursor: 'pointer' }} />
                </td>
                <td style={{ padding: '15px', fontWeight: 'bold', color: 'var(--p-purple)' }}>{student.serial}</td>
                <td style={{ padding: '15px' }}><div style={{ fontWeight: 'bold', textDecoration: student.status === 'banned' ? 'line-through' : 'none' }}>{student.name}</div><div style={{ fontSize: '0.8rem', color: 'var(--txt-mut)' }}>📱 {student.phone}</div></td>
                
                {/* 💡 بيانات الباسورد رجعت هنا */}
                <td style={{ padding: '15px', fontFamily: 'monospace', color: 'var(--warning)', fontWeight: 'bold', letterSpacing: '1px' }}>{student.password}</td>
                
                <td style={{ padding: '15px' }}>
                    {student.status === 'banned' 
                        ? <span style={{ background: 'rgba(231,76,60,0.1)', color: 'var(--danger)', padding: '5px 10px', borderRadius: '8px', fontSize: '0.85rem', fontWeight: 'bold' }}>🚫 محظور</span>
                        : <span style={{ background: 'rgba(46,204,113,0.1)', color: 'var(--success)', padding: '5px 10px', borderRadius: '8px', fontSize: '0.85rem', fontWeight: 'bold' }}>✅ نشط</span>
                    }
                </td>
                <td style={{ padding: '15px', color: 'var(--txt-mut)' }}>{student.grade}</td>
                <td style={{ padding: '15px', textAlign: 'center' }}>
                    <Button variant="outline" size="sm" onClick={() => { setSelectedStudent(student); setView('profile'); }}>فتح الملف</Button>
                </td>
            </tr>
        ))}
    </tbody>
</table>

                            <div className="mobile-cards" style={{ padding: '15px' }}>
                                {currentStudents.map(student => (
                                    <div key={student.id} style={{ background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.05)', borderRadius: '15px', padding: '15px' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                                            <strong style={{ color: 'var(--p-purple)' }}>{student.serial}</strong>
                                            <input type="checkbox" checked={selectedIds.includes(student.id)} onChange={() => toggleSelectOne(student.id)} style={{ width: '20px', height: '20px', accentColor: 'var(--p-purple)' }} />
                                        </div>
                                        <div style={{ fontWeight: 'bold', fontSize: '1.1rem', marginBottom: '5px', textDecoration: student.status === 'banned' ? 'line-through' : 'none' }}>{student.name}</div>
                                        <div style={{ color: 'var(--txt-mut)', fontSize: '0.9rem', marginBottom: '10px' }}>📱 {student.phone}</div>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', borderTop: '1px dashed rgba(255,255,255,0.1)', paddingTop: '10px' }}>
                                            <span style={{ color: 'var(--warning)', fontFamily: 'monospace' }}>{student.password}</span>
                                            <Button variant="outline" size="sm" onClick={() => { setSelectedStudent(student); setView('profile'); }}>فتح الملف</Button>
                                        </div>
                                    </div>
                                ))}
                            </div>

                            <div style={{ padding: '15px', display: 'flex', justifyContent: 'center', gap: '10px', background: 'rgba(0,0,0,0.2)' }}>
                                <button disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)} style={{ padding: '8px 15px', background: 'var(--card)', border: '1px solid rgba(255,255,255,0.1)', color: 'var(--txt)', borderRadius: '8px', cursor: currentPage === 1 ? 'not-allowed' : 'pointer' }}>السابق</button>
                                <span style={{ padding: '8px 15px', fontWeight: 'bold', color: 'var(--p-purple)' }}>{currentPage} / {totalPages || 1}</span>
                                <button disabled={currentPage >= totalPages} onClick={() => setCurrentPage(p => p + 1)} style={{ padding: '8px 15px', background: 'var(--card)', border: '1px solid rgba(255,255,255,0.1)', color: 'var(--txt)', borderRadius: '8px', cursor: currentPage >= totalPages ? 'not-allowed' : 'pointer' }}>التالي</button>
                            </div>
                        </div>
                    </>
                )}

                {dashboardTab === 'map' && (
                    <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
                        <div style={{ flex: '1 1 500px', background: 'var(--card)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', padding: '20px', display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '600px', position: 'relative', overflow: 'hidden' }}>
                            <svg viewBox="0 0 1000 888" style={{ width: '100%', height: '100%', maxWidth: '500px', filter: 'drop-shadow(0 15px 25px rgba(0,0,0,0.5))', zIndex: 2 }}>
                                {EGYPT_REGIONS.map((region) => (
                                    <path key={region.id} id={region.id} d={region.path} fill={hoveredRegion?.id === region.id ? region.color : `${region.color}e6`} className="egypt-map-path" onMouseEnter={() => setHoveredRegion(region)} onMouseLeave={() => setHoveredRegion(null)} onClick={() => showToast(`تم تحديد محافظة ${region.name}`, 'info')} />
                                ))}
                            </svg>
                        </div>
                        <div style={{ flex: '1 1 350px', display: 'flex', flexDirection: 'column', gap: '15px' }}>
                            {hoveredRegion ? (
                                <div style={{ background: 'var(--card)', borderRadius: '20px', border: `2px solid ${hoveredRegion.color}`, padding: '30px', animation: 'fadeIn 0.3s ease', height: '100%' }}>
                                    <h2 style={{ color: hoveredRegion.color, fontSize: '1.8rem', fontWeight: 900, marginBottom: '10px' }}>{hoveredRegion.name}</h2>
                                    <div style={{ fontSize: '2.5rem', fontWeight: 900, color: 'var(--txt)', marginBottom: '20px' }}>{hoveredRegion.count.toLocaleString()} <span style={{fontSize:'1rem', color:'var(--txt-mut)'}}>طالب مسجل</span></div>
                                    <div style={{ background: 'rgba(0,0,0,0.2)', padding: '15px', borderRadius: '12px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px dashed rgba(255,255,255,0.1)', paddingBottom: '10px' }}><span style={{ color: 'var(--txt-mut)' }}>الصف الأول:</span> <strong style={{ color: 'var(--txt)' }}>{hoveredRegion.breakdown?.['الصف الأول الثانوي']?.toLocaleString() || 0}</strong></div>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px dashed rgba(255,255,255,0.1)', paddingBottom: '10px' }}><span style={{ color: 'var(--txt-mut)' }}>الصف الثاني:</span> <strong style={{ color: 'var(--txt)' }}>{hoveredRegion.breakdown?.['الصف الثاني الثانوي']?.toLocaleString() || 0}</strong></div>
                                        <div style={{ display: 'flex', justifyContent: 'space-between' }}><span style={{ color: 'var(--txt-mut)' }}>الصف الثالث:</span> <strong style={{ color: 'var(--p-purple)' }}>{hoveredRegion.breakdown?.['الصف الثالث الثانوي']?.toLocaleString() || 0}</strong></div>
                                    </div>
                                </div>
                            ) : (
                                <div style={{ background: 'var(--card)', borderRadius: '20px', border: '1px dashed rgba(255,255,255,0.1)', padding: '30px', height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', textAlign: 'center', color: 'var(--txt-mut)' }}>
                                    <FaMapMarkerAlt style={{ fontSize: '4rem', opacity: 0.2, marginBottom: '15px' }} />
                                    <h3>مرر الماوس على الخريطة</h3>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                <Modal isOpen={isBulkBalanceModalOpen} onClose={() => setIsBulkBalanceModalOpen(false)} title="إضافة رصيد" maxWidth="400px">
                    <div style={{ padding: '10px 0' }}>
                        <Input label="المبلغ (ج.م)" type="number" value={bulkAmount} onChange={(e) => setBulkAmount(e.target.value)} />
                        <Button variant="primary" fullWidth onClick={handleBulkAddBalance} style={{ marginTop: '15px' }}>تأكيد الشحن</Button>
                    </div>
                </Modal>
            </div>
        );
    }

    if (view === 'profile' && selectedStudent) {
        return (
            <div style={{ animation: 'fadeIn 0.5s ease' }}>
                <Button variant="outline" icon={<FaArrowRight />} onClick={() => setView('dashboard')} style={{ marginBottom: '20px' }}>العودة للجدول</Button>

                <div style={{ display: 'flex', gap: '30px', flexWrap: 'wrap', alignItems: 'flex-start' }}>
                    <div style={{ flex: '1 1 320px', display: 'flex', flexDirection: 'column', gap: '20px', position: 'sticky', top: '20px' }}>
                        <div style={{ background: 'var(--card)', padding: '25px', borderRadius: '20px', border: selectedStudent.status === 'banned' ? '2px solid var(--danger)' : '1px solid rgba(255,255,255,0.05)', textAlign: 'center', position: 'relative' }}>
                            {selectedStudent.status === 'banned' && (
                                <div style={{ position: 'absolute', top: '15px', right: '15px', background: 'var(--danger)', color: 'white', padding: '5px 10px', borderRadius: '8px', fontSize: '0.8rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '5px' }}>
                                    <FaBan /> حساب محظور
                                </div>
                            )}
                            <div style={{ width: '80px', height: '80px', background: selectedStudent.status === 'banned' ? 'var(--danger)' : 'linear-gradient(45deg, var(--p-purple), #ff007f)', borderRadius: '50%', display: 'flex', justifyContent: 'center', alignItems: 'center', fontSize: '2.5rem', fontWeight: 900, color: 'white', margin: '0 auto 15px' }}>{selectedStudent.name.charAt(0)}</div>
                            <h2 style={{ fontSize: '1.4rem', color: selectedStudent.status === 'banned' ? 'var(--danger)' : 'var(--txt)', marginBottom: '5px', textDecoration: selectedStudent.status === 'banned' ? 'line-through' : 'none' }}>{selectedStudent.name}</h2>
                            <p style={{ color: 'var(--txt-mut)', marginBottom: '5px' }}>{selectedStudent.grade} - {selectedStudent.gov}</p>
                            <p style={{ color: 'var(--warning)', fontFamily: 'monospace', fontWeight: 'bold', marginBottom: '15px' }}>{selectedStudent.serial}</p>
                            
                            <div style={{ display: 'flex', gap: '10px', marginBottom: '15px' }}>
                                <Button variant="outline" fullWidth icon={<FaUserEdit />} onClick={() => { setEditFormData(selectedStudent); setIsEditModalOpen(true); }}>تعديل</Button>
                                <Button variant="outline" style={{ color: 'var(--warning)', borderColor: 'var(--warning)' }} icon={<FaSyncAlt />} onClick={() => resetIP(selectedStudent.name)} title="تصفير الأجهزة"></Button>
                            </div>
                            
                            <Button 
                                variant={selectedStudent.status === 'banned' ? 'primary' : 'outline'} 
                                fullWidth 
                                icon={selectedStudent.status === 'banned' ? <FaUnlock /> : <FaBan />} 
                                onClick={toggleStudentBan}
                                style={{ background: selectedStudent.status === 'banned' ? 'var(--success)' : 'transparent', color: selectedStudent.status === 'banned' ? 'white' : 'var(--danger)', borderColor: selectedStudent.status === 'banned' ? 'var(--success)' : 'var(--danger)' }}
                            >
                                {selectedStudent.status === 'banned' ? 'فك الحظر عن الطالب' : 'حظر الطالب نهائياً'}
                            </Button>

                            <div style={{ background: 'rgba(241, 196, 15, 0.1)', border: '1px solid var(--warning)', padding: '15px', borderRadius: '15px', marginTop: '20px' }}>
                                <div style={{ color: 'var(--txt-mut)', fontSize: '0.85rem' }}><FaWallet/> محفظة الطالب</div>
                                <div style={{ fontSize: '1.8rem', fontWeight: 900, color: 'var(--txt)' }}>{selectedStudent.balance} ج.م</div>
                            </div>
                        </div>

                        <div style={{ background: 'var(--card)', padding: '20px', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)' }}>
                            <h3 style={{ fontSize: '1.1rem', color: 'var(--txt)', fontWeight: 900, marginBottom: '15px', display: 'flex', alignItems: 'center', gap: '8px' }}><FaNetworkWired color="var(--danger)"/> سجل الأمان</h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', fontSize: '0.9rem' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between' }}><span style={{ color: 'var(--txt-mut)' }}><FaClock/> آخر ظهور:</span> <strong>{selectedStudent.lastLogin}</strong></div>
                                <div style={{ display: 'flex', justifyContent: 'space-between' }}><span style={{ color: 'var(--txt-mut)' }}><FaDesktop/> آخر جهاز:</span> <strong>{selectedStudent.lastDevice}</strong></div>
                                <div style={{ display: 'flex', justifyContent: 'space-between' }}><span style={{ color: 'var(--txt-mut)' }}>🌐 آخر IP:</span> <strong style={{ color: 'var(--warning)' }}>{selectedStudent.lastIP}</strong></div>
                            </div>
                        </div>
                    </div>

                    <div style={{ flex: '2 1 600px', display: 'flex', flexDirection: 'column', gap: '20px' }}>
                        <div style={{ display: 'flex', gap: '10px', background: 'var(--card)', padding: '10px', borderRadius: '15px', border: '1px solid rgba(255,255,255,0.05)', flexWrap: 'wrap' }}>
                            <button onClick={() => setProfileTab('timeline')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', fontWeight: 'bold', cursor: 'pointer', transition: '0.3s', background: profileTab === 'timeline' ? 'var(--p-purple)' : 'transparent', color: profileTab === 'timeline' ? 'white' : 'var(--txt)' }}>سجل التحركات</button>
                            <button onClick={() => setProfileTab('academic')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', fontWeight: 'bold', cursor: 'pointer', transition: '0.3s', background: profileTab === 'academic' ? 'var(--success)' : 'transparent', color: profileTab === 'academic' ? 'white' : 'var(--txt)' }}>الأداء الأكاديمي</button>
                            <button onClick={() => setProfileTab('financial')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', fontWeight: 'bold', cursor: 'pointer', transition: '0.3s', background: profileTab === 'financial' ? 'var(--warning)' : 'transparent', color: profileTab === 'financial' ? 'white' : 'var(--txt)' }}>الماليات والمشتريات</button>
                        </div>

                        {profileTab === 'timeline' && (
                            <div style={{ background: 'var(--card)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', padding: '25px', animation: 'fadeIn 0.3s ease' }}>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '20px', position: 'relative', paddingRight: '15px', borderRight: '2px solid rgba(255,255,255,0.1)' }}>
                                    {selectedStudent.timeline.map((act: any) => (
                                        <div key={act.id} style={{ position: 'relative' }}>
                                            <div style={{ position: 'absolute', right: '-26px', top: '0', width: '20px', height: '20px', background: 'var(--card)', border: `2px solid ${act.type === 'error' ? 'var(--danger)' : 'var(--p-purple)'}`, borderRadius: '50%', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2 }}>
                                                {renderTimelineIcon(act.type)}
                                            </div>
                                            <div style={{ background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.05)', padding: '15px', borderRadius: '10px', marginRight: '15px' }}>
                                                <div style={{ fontWeight: 'bold', color: 'var(--txt)', marginBottom: '5px' }}>{act.text}</div>
                                                <div style={{ fontSize: '0.8rem', color: 'var(--txt-mut)' }}>{act.time}</div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {profileTab === 'academic' && (
                            <div style={{ background: 'var(--card)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', padding: '25px', animation: 'fadeIn 0.3s ease' }}>
                                <table style={{ width: '100%', textAlign: 'right', borderCollapse: 'collapse' }}>
                                    <thead>
                                        <tr style={{ background: 'rgba(255,255,255,0.05)', color: 'var(--txt-mut)' }}>
                                            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>الامتحان / الواجب</th>
                                            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>النوع</th>
                                            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)', textAlign: 'center' }}>الدرجة</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {selectedStudent.academicRecord.map((record: any, idx: number) => {
                                            const color = (record.score / record.total) >= 0.85 ? 'var(--success)' : (record.score / record.total) >= 0.5 ? 'var(--warning)' : 'var(--danger)';
                                            return (
                                                <tr key={idx} style={{ borderBottom: '1px dashed rgba(255,255,255,0.05)' }}>
                                                    <td style={{ padding: '15px', fontWeight: 'bold', color: 'var(--txt)' }}>{record.title}</td>
                                                    <td style={{ padding: '15px', color: 'var(--txt-mut)' }}>{record.type}</td>
                                                    <td style={{ padding: '15px', textAlign: 'center', fontWeight: 'bold', color }}>{record.score} / {record.total}</td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>
                        )}

                        {profileTab === 'financial' && (
                            <div style={{ background: 'var(--card)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', padding: '25px', animation: 'fadeIn 0.3s ease' }}>
                                <h3 style={{ fontSize: '1.2rem', color: 'var(--txt)', fontWeight: 900, marginBottom: '20px' }}><FaBarcode color="var(--success)" /> سجل شحن الأكواد</h3>
                                <table style={{ width: '100%', textAlign: 'right', borderCollapse: 'collapse', marginBottom: '30px' }}>
                                    <thead>
                                        <tr style={{ background: 'rgba(255,255,255,0.05)', color: 'var(--txt-mut)' }}>
                                            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>الكود</th>
                                            <th style={{ padding: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)', textAlign: 'center' }}>القيمة</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {selectedStudent.chargingLogs.map((log: any) => (
                                            <tr key={log.id} style={{ borderBottom: '1px dashed rgba(255,255,255,0.05)' }}>
                                                <td style={{ padding: '15px', fontFamily: 'monospace', color: 'var(--txt-mut)' }}>{log.code}</td>
                                                <td style={{ padding: '15px', textAlign: 'center', fontWeight: 'bold', color: 'var(--success)' }}>+{log.amount} ج.م</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                </div>

                <Modal isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} title="تعديل بيانات الطالب" maxWidth="600px">
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '15px', padding: '10px 0' }}>
                        <Input label="الاسم" value={editFormData.name || ''} onChange={e => setEditFormData({...editFormData, name: e.target.value})} />
                        <Input label="المحافظة" value={editFormData.gov || ''} onChange={e => setEditFormData({...editFormData, gov: e.target.value})} />
                        <Input label="تليفون الطالب" value={editFormData.phone || ''} onChange={e => setEditFormData({...editFormData, phone: e.target.value})} />
                        <Input label="تليفون ولي الأمر" value={editFormData.parentPhone || ''} onChange={e => setEditFormData({...editFormData, parentPhone: e.target.value})} />
                        <Input label="الباسورد" value={editFormData.password || ''} onChange={e => setEditFormData({...editFormData, password: e.target.value})} />
                        <Input label="المرحلة الدراسية" value={editFormData.grade || ''} onChange={e => setEditFormData({...editFormData, grade: e.target.value})} />
                    </div>
                    <div style={{ display: 'flex', gap: '15px', marginTop: '25px' }}>
                        <Button variant="primary" fullWidth icon={<FaSave />} onClick={saveStudentEdit}>حفظ التعديلات</Button>
                        <Button variant="outline" fullWidth onClick={() => setIsEditModalOpen(false)}>إلغاء</Button>
                    </div>
                </Modal>
            </div>
        );
    }

    return null;
}